const games = $json.body;

const output = [];

Object.keys(games).forEach(key => {
  const game = games[key];

  if (game && game.teams) {
    const isoDate = game.gameDate;
    const dateObj = new Date(isoDate);

    // Subtract 5 hours for CDT (Central Daylight Time)
    dateObj.setHours(dateObj.getHours() - 5);

    const datePart = dateObj.toISOString().split('T')[0];
    const timePart = dateObj.toISOString().split('T')[1].replace('Z', '').slice(0, 8);

    output.push({
      date: datePart,           // Central Date
      time: timePart,           // Central Time
      awayTeam: game.teams.away.team.name,
      awayWins: game.teams.away.leagueRecord.wins,
      awayLosses: game.teams.away.leagueRecord.losses,
      awayWinPct: game.teams.away.leagueRecord.pct,
      homeTeam: game.teams.home.team.name,
      homeWins: game.teams.home.leagueRecord.wins,
      homeLosses: game.teams.home.leagueRecord.losses,
      homeWinPct: game.teams.home.leagueRecord.pct,
      venue: game.venue.name,
      gameStatus: game.status.detailedState,
      dayNight: game.dayNight,
      scheduledInnings: game.scheduledInnings,
      gamePk: game.gamePk
    });
  }
});

return output.map(record => ({ json: record }));

const output = [];

for (const item of items) {
  const events = item.json.events || [];

  for (const game of events) {
    const period0 = game.periods?.num_0;
    const moneyLine = period0?.money_line;

    if (moneyLine && moneyLine.home && moneyLine.away) {
      output.push({
        json: {
          event_id: game.event_id,
          home_team: game.home,
          away_team: game.away,
          start_time: game.starts,
          home_odds: moneyLine.home,
          away_odds: moneyLine.away
        }
      });
    }
  }
}

return output;

return items.map(item => {
  const data = item.json;

  const homeOdds = parseFloat(data.home_odds);
  const awayOdds = parseFloat(data.away_odds);
  const homeWinPct = parseFloat(data.homeWinPct);
  const awayWinPct = parseFloat(data.awayWinPct);

  // Avoid division by zero
  if (!homeOdds || !awayOdds || !homeWinPct || !awayWinPct) {
    return { json: { ...data, note: "Missing or invalid input data" } };
  }

  const totalWinPct = homeWinPct + awayWinPct;
  const modelHomeProb = homeWinPct / totalWinPct;
  const modelAwayProb = awayWinPct / totalWinPct;

  const impliedHomeProb = 1 / homeOdds;
  const impliedAwayProb = 1 / awayOdds;

  const homeEV = (modelHomeProb * (homeOdds - 1)) - (1 - modelHomeProb);
  const awayEV = (modelAwayProb * (awayOdds - 1)) - (1 - modelAwayProb);

  const homeKelly = ((homeOdds - 1) * modelHomeProb - (1 - modelHomeProb)) / (homeOdds - 1);
  const awayKelly = ((awayOdds - 1) * modelAwayProb - (1 - modelAwayProb)) / (awayOdds - 1);

  // New: Model Edge = Model Prob - Implied Prob
  const homeEdge = modelHomeProb - impliedHomeProb;
  const awayEdge = modelAwayProb - impliedAwayProb;

  return {
    json: {
      ...data,
      modelHomeProb: modelHomeProb.toFixed(4),
      modelAwayProb: modelAwayProb.toFixed(4),
      impliedHomeProb: impliedHomeProb.toFixed(4),
      impliedAwayProb: impliedAwayProb.toFixed(4),
      homeEdge: homeEdge.toFixed(4),         // NEW
      awayEdge: awayEdge.toFixed(4),         // NEW
      homeEV: homeEV.toFixed(4),
      awayEV: awayEV.toFixed(4),
      homeKelly: homeKelly.toFixed(4),
      awayKelly: awayKelly.toFixed(4)
    }
  };
});

